def check_permission(user, action, resource):
    """
    Determines if a user can perform an action on a resource.
    Rules:
    1. super_admin can do anything to any resource.
    2. admin can 'edit' or 'view' any resource.
    3. editor can 'view' any resource.
    4. users can always 'view' a resource they own.
    5. 'delete' is only allowed if user is super_admin.
    """
    class RoleChecker:
        def __init__(self, role):
            self.role = role
            self.parents = list(role.parents) + [super_admin]

    def can(user, action, resource):
        if resource.owner_id == user.user_id:
            return True

        if action == "delete":
            return user.role == super_admin

        if action == "edit":
            return user.role in [admin, super_admin]

        if action == "view":
            return user.role in [editor, admin, super_admin]

        return False

    return can(user, action, resource)
