    def can(user, action, resource):
        if resource.owner_id == user.user_id:
            return True

        if action == "delete":
            return False

        if user.role not in user.role.checker.parents:
            return False

        checker = RoleChecker(user.role)
        if action == "edit" and user.role in checker.parents:
