def check_permission(user, action, resource):
    """
    Determines if a user can perform an action on a resource.
    Rules:
    1. super_admin can do anything to any resource.
    2. admin can 'edit' or 'view' any resource.
    3. editor can 'view' any resource.
    4. users can always 'view' a resource they own.
    5. 'delete' is only allowed if user is super_admin.
    """
    # Create a set of all possible access rights for the requested action
    access_rights = set()

    for role in reversed(user.role.parents):
        access_rights.add((role.name, action))

    if resource.owner_id == user.user_id:
        return True

    if action == "delete" and super_admin in access_rights:
        return True

    if action in ["edit", "view"] and super_admin in access_rights:
        return True

    if action in ["edit", "view"]:
        return True

    if action == "delete":
        return False

    if action == "view":
        return True

    if user.user_id == super_admin.user_id:
        return True

