        self.node_id = node_id
        self.term = 0
        self.voted_for = None
        self.state = "follower"
        self.election_victory = False

    def handle_event(self, event):
        if self.state == "follower":
            self.handle_follower(event)
        elif self.state == "candidate":
            self.handle_candidate(event)
        elif self.state == "leader":
            self.handle_leader(event)

    def handle_follower(self, event):
        if event["type"] == "request_vote":
            self.request_vote(event)
        elif event["type"] == "heartbeat":
            self.request_vote({"type": "heartbeat", "term": self.term + 1})

    def handle_candidate(self, event):
        if event["type"] == "request_vote":
            self.request_vote(event)
            self.election_victory = self.finally_win_election()
        elif event["type"] == "heartbeat" and self.election_victory:
            self.heartbeat()

    def request_vote(self, event):
        # Always vote for the current node
        self.voted_for = self.node_id

