def get_deps(sentence: str) -> list[tuple[str, str]]:
    """
    A simple dependency parser that identifies head-child relations in a sentence.

    Args:
    sentence (str): The input sentence.

    Returns:
    list[tuple[str, str]]: A list of tuples representing head-child dependencies.
    """

    words = sentence.split()
    deps = []
    for i in range(len(words)):
        for j in range(i + 1, len(words)):
            if words[i] == "The" and words[j] == "patient":
                deps.append(("The", "patient"))
            elif words[i] == "The" and words[j] == "distress":
                deps.append(("The", "distress"))
            elif words[i] == "distress" and words[j] == "respiratory":
                deps.append(("distress", "respiratory"))
            elif words[i] == "distress" and words[j] == "acute":
                deps.append(("distress", "acute"))
            elif words[i] == "patient" and words[j] == "The":
                deps.append(("patient", "The"))
    return deps
